// src/audit/audit.processor.spec.ts
import { Test, TestingModule } from '@nestjs/testing';
import { Logger } from '@nestjs/common';
import { AuditProcessor } from './audit.processor';
import { PrismaService } from '../prisma/prisma.service';
import { AuditOutboxStatus, Prisma } from '@prisma/client';

describe('AuditProcessor', () => {
  let processor: AuditProcessor;
  let prisma: {
    auditOutbox: {
      findMany: jest.Mock;
      update: jest.Mock;
      create: jest.Mock;
    };
    auditLog: {
      create: jest.Mock;
    };
    $transaction: jest.Mock;
  };

  const mockLogger = {
    error: jest.fn(),
    log: jest.fn(),
    warn: jest.fn(),
    debug: jest.fn(),
  };

  beforeEach(async () => {
    prisma = {
      auditOutbox: {
        findMany: jest.fn(),
        update: jest.fn(),
        create: jest.fn(),
      },
      auditLog: {
        create: jest.fn(),
      },
      $transaction: jest.fn((callback) => callback(prisma)),
    };

    const module: TestingModule = await Test.createTestingModule({
      providers: [
        AuditProcessor,
        {
          provide: PrismaService,
          useValue: prisma,
        },
      ],
    }).compile();

    processor = module.get<AuditProcessor>(AuditProcessor);
    
    // Mock the logger
    jest.spyOn(Logger.prototype, 'error').mockImplementation(mockLogger.error);
    jest.spyOn(Logger.prototype, 'log').mockImplementation(mockLogger.log);
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  describe('process', () => {
    const mockOutboxItem = {
      id: BigInt(1),
      payload: {
        entityType: 'User',
        entityId: '123',
        action: 'CREATE',
      },
      status: AuditOutboxStatus.PENDING,
      attempts: 0,
      lastError: null,
      createdAt: new Date(),
    };

    it('should process pending audit outbox items', async () => {
      prisma.auditOutbox.findMany.mockResolvedValue([mockOutboxItem]);
      prisma.auditLog.create.mockResolvedValue({ id: BigInt(1) });
      prisma.auditOutbox.update.mockResolvedValue({});

      await processor.process();

      expect(prisma.auditOutbox.findMany).toHaveBeenCalledWith({
        where: { status: AuditOutboxStatus.PENDING },
        take: 100,
        orderBy: { createdAt: 'asc' },
      });
      expect(prisma.auditLog.create).toHaveBeenCalledWith({
        data: mockOutboxItem.payload,
      });
      expect(prisma.auditOutbox.update).toHaveBeenCalledWith({
        where: { id: mockOutboxItem.id },
        data: {
          status: AuditOutboxStatus.PROCESSED,
          processedAt: expect.any(Date),
        },
      });
    });

    it('should not throw when no pending items', async () => {
      prisma.auditOutbox.findMany.mockResolvedValue([]);

      await expect(processor.process()).resolves.toBeUndefined();
      expect(prisma.auditLog.create).not.toHaveBeenCalled();
    });

    it('should handle processing failures and update status to FAILED', async () => {
      const failingItem = { ...mockOutboxItem, attempts: 2 };
      prisma.auditOutbox.findMany.mockResolvedValue([failingItem]);
      prisma.auditLog.create.mockRejectedValue(new Error('Database error'));

      await processor.process();

      expect(prisma.auditOutbox.update).toHaveBeenCalledWith({
        where: { id: failingItem.id },
        data: {
          attempts: 3,
          status: AuditOutboxStatus.FAILED,
          lastError: expect.any(String),
        },
      });
    });

    it('should move item to DEAD_LETTER after 5 failed attempts', async () => {
      const failingItem = { ...mockOutboxItem, attempts: 4 };
      prisma.auditOutbox.findMany.mockResolvedValue([failingItem]);
      prisma.auditLog.create.mockRejectedValue(new Error('Database error'));

      await processor.process();

      expect(prisma.auditOutbox.update).toHaveBeenCalledWith({
        where: { id: failingItem.id },
        data: {
          attempts: 5,
          status: AuditOutboxStatus.DEAD_LETTER,
          lastError: expect.any(String),
        },
      });
    });

    it('should process multiple items in a batch', async () => {
      const items = [
        mockOutboxItem,
        { ...mockOutboxItem, id: BigInt(2) },
        { ...mockOutboxItem, id: BigInt(3) },
      ];
      prisma.auditOutbox.findMany.mockResolvedValue(items);
      prisma.auditLog.create.mockResolvedValue({ id: BigInt(1) });
      prisma.auditOutbox.update.mockResolvedValue({});

      await processor.process();

      expect(prisma.auditLog.create).toHaveBeenCalledTimes(3);
      expect(prisma.auditOutbox.update).toHaveBeenCalledTimes(3);
    });

    it('should continue processing other items if one fails', async () => {
      const items = [
        mockOutboxItem,
        { ...mockOutboxItem, id: BigInt(2) },
      ];
      prisma.auditOutbox.findMany.mockResolvedValue(items);
      
      // First succeeds, second fails
      prisma.auditLog.create
        .mockResolvedValueOnce({ id: BigInt(1) })
        .mockRejectedValueOnce(new Error('Database error'));
      
      prisma.auditOutbox.update.mockResolvedValue({});

      await processor.process();

      expect(prisma.auditLog.create).toHaveBeenCalledTimes(2);
      expect(prisma.auditOutbox.update).toHaveBeenCalledTimes(2);
    });
  });
});
